3	// Order summary query — combines order + account + line items + invoice + shipment info.
4	// Reads from: orders (with embedded lineItems), accounts, invoices, shipments collections.
5	// This query must be updated to include preferredPaymentMethod from the account.
6	
7	export async function getOrderSummary(db, orderId) {
8		await ensureSchema(db);
9		const order = await db.collection("orders").findOne({ orderId });
10		if (!order) return null;
11		const account = await db.collection("accounts").findOne({ accountId: order.accountId });
12		const invoice = await db.collection("invoices").findOne({ orderId });
13		const shipment = await db.collection("shipments").findOne({ orderId });
14		return {
15			orderId: order.orderId,
16			status: order.status,
17			totalCents: order.totalCents,
18			currency: order.currency,
19			lineItems: order.lineItems || [],
20			accountName: account?.name,
21			accountTier: account?.tier,
22			invoiceStatus: invoice?.status,
23			invoiceAmountCents: invoice?.amountCents,
24			shipmentStatus: shipment?.status,
25			carrier: shipment?.carrier,
26		};
27	}
